{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "topic": "배포 목표",
        "decision": "공개 배포 목표는 금요일 15:00 KST로 잡되, 스모크 테스트가 통과해야 한다."
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약(contract) 자체가 잘못된 경우에만 스크립트 검토로 넘어간다."
      }
    ],
    "rejected_proposals": [
      {
        "topic": "배포 시점",
        "proposal": "수요일 배포",
        "result": "거절됨",
        "reason": "스모크 테스트 통과가 선행되어야 한다."
      },
      {
        "topic": "smoke-theme-pack.mjs 수정",
        "proposal": "packageName 불일치를 무시하도록 스크립트를 변경",
        "result": "거절됨",
        "reason": "우선 패키지 설정과 계약 일치 여부를 확인해야 한다."
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "내부 목표",
        "goal": "수요일 배포 시도",
        "status": "내부 스트레치 목표로만 언급됨",
        "note": "공개 배포 확정 일정은 아니며, 스모크 통과 여부와 별개로 내부 목표 수준이다."
      },
      {
        "topic": "README 검토",
        "goal": "README 설치 단계를 목요일까지 검토",
        "status": "가능하면 진행",
        "note": "소유자와 확정 일정은 지정되지 않았다."
      }
    ],
    "non_decisions": [
      {
        "topic": "외부 고객/파트너",
        "status": "언급되지 않음",
        "note": "고객 또는 외부 파트너는 명시되지 않았다."
      },
      {
        "topic": "최종 승인 권한",
        "status": "미결정"
      },
      {
        "topic": "릴리스 노트에 내부 수요일 목표 포함 여부",
        "status": "미결정"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로",
        "impact": "릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래됨",
        "impact": "릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있다."
      }
    ],
    "open_questions": [
      "누가 최종 릴리스 승인 권한을 갖는가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": "다음 확인 항목은 스모크 테스트 결과, tarball 경로, README 설치 단계의 최신성, 그리고 최종 릴리스 승인권자이다. 확인되지 않은 고객명, 예산, 보안 사고, 운영 중단, 법적 승인, 소유자, 마감일은 만들어내지 말아야 한다.",
  "non_invention_rules": [
    "고객명은 추측하지 않는다.",
    "예산 정보는 추측하지 않는다.",
    "보안 사고는 추측하지 않는다.",
    "생산 장애는 추측하지 않는다.",
    "법적 승인 요구는 추측하지 않는다.",
    "소유자 없는 작업의 담당자는 임의 지정하지 않는다.",
    "명시되지 않은 마감일은 임의로 만들지 않는다.",
    "fixture에 없는 사실은 확정된 것처럼 쓰지 않는다."
  ]
}
